  z.object({
    /**
     * The artistic style for the generated pixel art image.
     *
     * - `'pixel'`: Classic pixel art style
     * - `'retro'`: Retro game-inspired style
     * - `'8bit'`: 8-bit era game art style
     */
    style: z.enum(['pixel', 'retro', '8bit']).nullish(),

    /**
     * The pixel density of the output image.
     * Higher values produce more detailed pixel art.
     * Range: 1-100.
     */
    pixelDensity: z.number().min(1).max(100).nullish(),

    /**
     * The output image format.
     */
    outputFormat: z.enum(['png', 'jpeg', 'webp']).nullish(),
  }),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

