import type { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixel-art-image-model';

const prompt = 'A knight riding a dragon in pixel art style';

const baseImageResponse = {
  images: [
    {
      url: 'https://api.example.com/image.png',
      width: 1024,
      height: 1024,
    },
  ],
  model: 'pixelart-v1',
  created: 1700000000,
};

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelArt.image',
    baseURL: 'https://api.example.com',
    headers: headers ?? { Authorization: 'Bearer test-key' },
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/images/generate': {
      response: {
        type: 'json-value',
        body: baseImageResponse,
      },
    },
    'https://api.example.com/image.png': {
      response: {
        type: 'binary',
        body: Buffer.from('test-binary-content'),
      },
    },
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelArt.image');
      expect(model.modelId).toBe('pixelart-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  describe('doGenerate', () => {
    it('should send the correct request body with basic options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '1024x1024',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
        headers: undefined,
        abortSignal: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        size: '1024x1024',
        seed: 42,
      });
    });

    it('should send provider-specific options in snake_case', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelArt: {
            style: 'retro',
            pixelDensity: 16,
            outputFormat: 'png',
          },
        },
        headers: undefined,
        abortSignal: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 2,
        size: '512x512',
        style: 'retro',
        pixel_density: 16,
        output_format: 'png',
      });
    });

    it('should omit size when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: undefined,
        abortSignal: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('size');
      expect(body).not.toHaveProperty('seed');
    });

    it('should warn when aspectRatio is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
        headers: undefined,
        abortSignal: undefined,
      });

      expect(result.warnings).toHaveLength(1);
      expect(result.warnings[0]).toMatchObject({
        type: 'unsupported',
        feature: 'aspectRatio',
      });
    });

    it('should not include aspectRatio in the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
        headers: undefined,
        abortSignal: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('aspectRatio');
      expect(body).not.toHaveProperty('aspect_ratio');
    });

    it('should pass custom headers', async () => {
      const model = createBasicModel({
        headers: {
          'X-Custom-Header': 'custom-value',
        },
      });

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: {
          'X-Request-Header': 'request-value',
        },
        abortSignal: undefined,
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        'x-custom-header': 'custom-value',
        'x-request-header': 'request-value',
      });
    });

    it('should download and return images as Uint8Array', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '1024x1024',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: undefined,
        abortSignal: undefined,
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
    });

    it('should return correct response metadata', async () => {
      const testDate = new Date('2024-01-01T00:00:00Z');
      const model = createBasicModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: undefined,
        abortSignal: undefined,
      });

      expect(result.response).toStrictEqual({
        modelId: 'pixelart-v1',
        timestamp: testDate,
        headers: expect.any(Object),
      });
    });

    it('should include providerMetadata with pixelArt key', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: undefined,
        abortSignal: undefined,
      });

      expect(result.providerMetadata).toMatchObject({
        pixelArt: {
          images: [
            {
              url: 'https://api.example.com/image.png',
              width: 1024,
              height: 1024,
            },
          ],
          created: 1700000000,
        },
      });
    });

    it('should handle API errors', async () => {
      server.urls['https://api.example.com/images/generate'].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid prompt',
            type: 'invalid_request_error',
            code: 'invalid_prompt',
          },
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          headers: undefined,
          abortSignal: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt',
        statusCode: 400,
      });
    });

    it('should produce no warnings when no aspectRatio is passed', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelArt: { style: '8bit' },
        },
        headers: undefined,
        abortSignal: undefined,
      });

      expect(result.warnings).toHaveLength(0);
    });
  });
});

