import { NoSuchModelError } from '@ai-sdk/provider';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { PixelArtImageModel } from './pixel-art-image-model';
import { createPixelArt } from './pixel-art-provider';

vi.mock('./pixel-art-image-model', () => ({
  PixelArtImageModel: vi.fn(),
}));

describe('createPixelArt', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('image / imageModel', () => {
    it('should construct an image model with default configuration', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const modelId = 'pixelart-v1';

      const model = provider.image(modelId);

      expect(model).toBeInstanceOf(PixelArtImageModel);
      expect(PixelArtImageModel).toHaveBeenCalledWith(
        modelId,
        expect.objectContaining({
          provider: 'pixelArt.image',
          baseURL: 'https://api.pixelart.ai/v1',
        }),
      );
    });

    it('imageModel should be an alias for image', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const modelId = 'pixelart-v2';

      provider.imageModel(modelId);

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        modelId,
        expect.objectContaining({
          provider: 'pixelArt.image',
        }),
      );
    });

    it('should respect a custom baseURL', () => {
      const customBaseURL = 'https://custom.pixelart.example.com/v2';
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: customBaseURL,
      });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({
          baseURL: customBaseURL,
        }),
      );
    });

    it('should strip trailing slash from baseURL', () => {
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://custom.pixelart.example.com/v2/',
      });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({
          baseURL: 'https://custom.pixelart.example.com/v2',
        }),
      );
    });

    it('should pass a custom fetch implementation', () => {
      const mockFetch = vi.fn();
      const provider = createPixelArt({ apiKey: 'test-key', fetch: mockFetch });

      provider.image('pixelart-v2-hd');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v2-hd',
        expect.objectContaining({
          fetch: mockFetch,
        }),
      );
    });

    it('should pass a headers function', () => {
      const provider = createPixelArt({
        apiKey: 'test-key',
        headers: { 'X-Custom': 'value' },
      });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({
          headers: expect.any(Function),
        }),
      );
    });

    it('should support arbitrary model IDs', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      for (const modelId of ['pixelart-v1', 'pixelart-v2', 'pixelart-v2-hd', 'custom-model']) {
        vi.clearAllMocks();
        provider.image(modelId);
        expect(PixelArtImageModel).toHaveBeenCalledWith(
          modelId,
          expect.objectContaining({ provider: 'pixelArt.image' }),
        );
      }
    });
  });

  describe('unsupported model types', () => {
    it('should throw NoSuchModelError for languageModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.languageModel('gpt-4')).toThrowError(
        NoSuchModelError,
      );
    });

    it('should throw NoSuchModelError for embeddingModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.embeddingModel('text-embed')).toThrowError(
        NoSuchModelError,
      );
    });
  });
});

